import{_ as t,o as a,c as o,a2 as r}from"./chunks/framework.Crpw6aS5.js";const m=JSON.parse('{"title":"Automatic rules","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/rules.md","filePath":"en/guide/rules.md"}'),l={name:"en/guide/rules.md"};function d(i,e,n,s,c,u){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="automatic-rules" tabindex="-1">Automatic rules <a class="header-anchor" href="#automatic-rules" aria-label="Permalink to &quot;Automatic rules&quot;">​</a></h1><p>Rules allow you to automate the cleanup and organization of your Gmail mailbox. Define conditions and actions — Nid executes them for you.</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>A rule consists of:</p><ul><li><strong>Conditions</strong>: which emails to target (sender, subject, size, etc.)</li><li><strong>Action</strong>: what to do with those emails (delete, archive, label, etc.)</li><li><strong>Schedule</strong>: when to run the rule (manually, daily, weekly, etc.)</li></ul><blockquote><p>📸 <em>Suggested screenshot: Rules page with the list of configured rules (name, summarized conditions, action, schedule, active/inactive toggle)</em></p></blockquote><hr><h2 id="create-a-rule" tabindex="-1">Create a rule <a class="header-anchor" href="#create-a-rule" aria-label="Permalink to &quot;Create a rule&quot;">​</a></h2><ol><li>In <strong>Rules</strong>, click <strong>Create a rule</strong></li><li>Fill in the form fields</li></ol><blockquote><p>📸 <em>Suggested screenshot: rule creation form (modal) with conditions, action and schedule fields</em></p></blockquote><h3 id="conditions" tabindex="-1">Conditions <a class="header-anchor" href="#conditions" aria-label="Permalink to &quot;Conditions&quot;">​</a></h3><p>You can combine multiple conditions. <strong>All conditions</strong> must be met for an email to be targeted (AND logic).</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><code>from</code></td><td>Sender</td><td><code>newsletter@example.com</code></td></tr><tr><td><code>to</code></td><td>Recipient</td><td><code>my-alias@gmail.com</code></td></tr><tr><td><code>subject</code></td><td>Email subject</td><td><code>promotion</code></td></tr><tr><td><code>has_attachment</code></td><td>Has attachment</td><td><code>true</code> / <code>false</code></td></tr><tr><td><code>size_gt</code></td><td>Minimum size (in bytes)</td><td><code>5242880</code> (5 MB)</td></tr><tr><td><code>older_than</code></td><td>Minimum age</td><td><code>30d</code>, <code>6m</code>, <code>1y</code></td></tr><tr><td><code>label</code></td><td>Gmail label</td><td><code>INBOX</code>, <code>SPAM</code>, <code>Label_123</code></td></tr><tr><td><code>is_unread</code></td><td>Unread</td><td><code>true</code> / <code>false</code></td></tr></tbody></table><p>Available operators: <code>contains</code>, <code>equals</code> (exact match), <code>not_contains</code>, <code>gt</code> (greater than), <code>lt</code> (less than).</p><h3 id="actions" tabindex="-1">Actions <a class="header-anchor" href="#actions" aria-label="Permalink to &quot;Actions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Action</th><th>Description</th></tr></thead><tbody><tr><td><strong>Move to trash</strong></td><td>Sends emails to the Gmail trash</td></tr><tr><td><strong>Delete permanently</strong></td><td>Irreversible deletion</td></tr><tr><td><strong>Archive (Gmail)</strong></td><td>Removes from the inbox</td></tr><tr><td><strong>Archive to NAS</strong></td><td>Saves as EML on your NAS</td></tr><tr><td><strong>Add a label</strong></td><td>Applies a Gmail label</td></tr><tr><td><strong>Remove a label</strong></td><td>Removes a Gmail label</td></tr><tr><td><strong>Mark as read</strong></td><td>Marks emails as read</td></tr><tr><td><strong>Mark as unread</strong></td><td>Marks emails as unread</td></tr></tbody></table><h3 id="schedules" tabindex="-1">Schedules <a class="header-anchor" href="#schedules" aria-label="Permalink to &quot;Schedules&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td><strong>Manual</strong></td><td>Runs only on demand</td></tr><tr><td><strong>Hourly</strong></td><td>Runs every hour</td></tr><tr><td><strong>Daily</strong></td><td>Runs once a day</td></tr><tr><td><strong>Weekly</strong></td><td>Runs every Monday</td></tr><tr><td><strong>Monthly</strong></td><td>Runs on the 1st of each month</td></tr></tbody></table><hr><h2 id="rule-templates" tabindex="-1">Rule templates <a class="header-anchor" href="#rule-templates" aria-label="Permalink to &quot;Rule templates&quot;">​</a></h2><p>To get started quickly, Nid offers a <strong>library of pre-configured templates</strong>.</p><ol><li>Click <strong>Templates</strong> at the top of the Rules page</li><li>Browse templates by category: <ul><li><strong>Cleanup</strong>: delete promotional emails, old notifications</li><li><strong>Archive</strong>: archive invoices, old emails</li><li><strong>Organization</strong>: automatically label by sender</li></ul></li><li>Click <strong>Use</strong> on a template</li><li>The rule is created — modify it if needed then activate it</li></ol><blockquote><p>📸 <em>Suggested screenshot: rule templates drawer/panel with the 3 categories</em></p></blockquote><p>Template examples:</p><ul><li>&quot;Clean up GitHub notifications older than 30 days&quot;</li><li>&quot;Archive invoices older than 3 months&quot;</li><li>&quot;Delete unread newsletters older than 30 days&quot;</li></ul><hr><h2 id="preview-a-rule" tabindex="-1">Preview a rule <a class="header-anchor" href="#preview-a-rule" aria-label="Permalink to &quot;Preview a rule&quot;">​</a></h2><p>Before running a rule, you can <strong>preview</strong> it:</p><ol><li>Click <strong>Preview</strong> on an existing rule</li><li>Nid displays the list of emails matching the conditions</li><li>Verify that the targeted emails are the ones you expect</li><li>Click <strong>Run</strong> to launch the rule</li></ol><blockquote><p>📸 <em>Suggested screenshot: rule preview result with the list of matching emails</em></p></blockquote><hr><h2 id="run-a-rule" tabindex="-1">Run a rule <a class="header-anchor" href="#run-a-rule" aria-label="Permalink to &quot;Run a rule&quot;">​</a></h2><h3 id="manual-execution" tabindex="-1">Manual execution <a class="header-anchor" href="#manual-execution" aria-label="Permalink to &quot;Manual execution&quot;">​</a></h3><p>Click <strong>Run</strong> on a rule to launch it immediately. A job is created with real-time tracking.</p><h3 id="scheduled-execution" tabindex="-1">Scheduled execution <a class="header-anchor" href="#scheduled-execution" aria-label="Permalink to &quot;Scheduled execution&quot;">​</a></h3><p>If a schedule is configured (daily, weekly, etc.), the rule runs automatically. The <strong>Last run</strong> field indicates when the rule was last executed.</p><hr><h2 id="enable-disable-a-rule" tabindex="-1">Enable / disable a rule <a class="header-anchor" href="#enable-disable-a-rule" aria-label="Permalink to &quot;Enable / disable a rule&quot;">​</a></h2><p>The <strong>toggle</strong> next to each rule lets you enable or disable it without deleting it. A disabled rule is not executed during automatic schedules.</p><hr><h2 id="edit-and-delete" tabindex="-1">Edit and delete <a class="header-anchor" href="#edit-and-delete" aria-label="Permalink to &quot;Edit and delete&quot;">​</a></h2><ul><li>Click on a rule to open the editing form</li><li>The <strong>Delete</strong> button permanently deletes the rule</li></ul>',43)])])}const g=t(l,[["render",d]]);export{m as __pageData,g as default};
